"""
Production-style planner that validates the task graph before execution.
Uses Pydantic for schema enforcement and detects dependency cycles.
"""
from pydantic import BaseModel, field_validator
from typing import Optional
import anthropic, json, asyncio

client = anthropic.Anthropic()

class Subtask(BaseModel):
    id: str
    description: str
    depends_on: list[str] = []
    tool: str
    expected_output: str

    @field_validator("tool")
    @classmethod
    def valid_tool(cls, v):
        allowed = {"web_search", "code_exec", "summarise", "calculate", "lookup"}
        if v not in allowed:
            raise ValueError(f"Unknown tool: {v}. Must be one of {allowed}")
        return v

def detect_cycle(tasks: list[Subtask]) -> bool:
    """Kahn's algorithm for cycle detection."""
    graph = {t.id: set(t.depends_on) for t in tasks}
    in_degree = {t.id: 0 for t in tasks}
    for t in tasks:
        for dep in t.depends_on:
            in_degree[t.id] = in_degree.get(t.id, 0) + 1
    queue = [tid for tid, deg in in_degree.items() if deg == 0]
    visited = 0
    while queue:
        node = queue.pop()
        visited += 1
        for t in tasks:
            if node in t.depends_on:
                in_degree[t.id] -= 1
                if in_degree[t.id] == 0:
                    queue.append(t.id)
    return visited != len(tasks)  # True means cycle exists

PLANNER = """Output a JSON array of subtasks. Schema per item:
{"id":"t1","description":"...","depends_on":[],"tool":"web_search","expected_output":"..."}
Tools: web_search, code_exec, summarise, calculate, lookup. JSON only."""

def plan_validated(goal: str) -> list[Subtask]:
    raw = client.messages.create(
        model="claude-opus-4-5", max_tokens=1024,
        system=PLANNER,
        messages=[{"role": "user", "content": goal}],
    )
    data = json.loads(raw.content[0].text)
    tasks = [Subtask(**item) for item in data]
    if detect_cycle(tasks):
        raise ValueError("Planner produced a cyclic dependency graph")
    return tasks

tasks = plan_validated("Calculate the compound annual growth rate of Apple revenue 2019-2023 and plot a trend summary.")
for t in tasks:
    print(f"{t.id} ({t.tool}): {t.description}")

# Simplified sketch of the ticker-fetch executor
import httpx, asyncio

async def fetch_ticker(ticker: str, session: httpx.AsyncClient) -> dict:
    url = f"https://api.marketdata.example.com/v1/quote/{ticker}"
    r = await session.get(url, timeout=5.0)
    r.raise_for_status()
    return {"ticker": ticker, "data": r.json()}

async def fetch_all(tickers: list[str]) -> dict[str, dict]:
    async with httpx.AsyncClient() as session:
        tasks = [fetch_ticker(t, session) for t in tickers]
        results = await asyncio.gather(*tasks, return_exceptions=True)
    out = {}
    for ticker, result in zip(tickers, results):
        if isinstance(result, Exception):
            out[ticker] = {"ticker": ticker, "data": None, "error": str(result)}
        else:
            out[ticker] = result
    return out

